//Rodape.js
import React from 'react';

import LogoReact from '../../imagens/logo.svg';
import LogoGithub from '../../imagens/github.svg';
import styles from './Rodape.module.css';

function Rodape() {
    
    return (
        <>
        <ul className={styles.ListaRodape }>
            
            <ul className={styles.ItensRodape}>
                
                <span>Criado utilizando React.JS</span>
                <img src={LogoReact} className={styles.LogoRodapeReact} alt='ReactLogo' />
            </ul>

            <ul className={styles.ItensRodape}>
                <span>Hospedado em Git-Hub Pages</span>
                <img src={LogoGithub} className={styles.LogoRodape} alt='GitHubLogo' />
            </ul>

            <ul className={styles.ItensRodape}>
                <span>Obrigado 
                <a 
                href='https://www.freepik.com'
                target='_blank'
                rel='noopener noreferrer'> FreePik </a> 
                pelas imagens de fundo.</span>
            </ul>

        </ul>
        
            
    
        </>
    );
}

export default Rodape;