import React, { useState } from "react";

import styles from './FormularioComunicacao.module.css';
import { sendForm } from "emailjs-com"



function FormularioComunicacao() {
    const [nomePessoa,setnomepessoa] = useState('')
    const [assuntoEmail,setassuntoEmail] = useState('')
    const [mensagemEmail,setmensagemEmail] = useState('')
    const [dadoContato, setdadoContato] = useState('')
    
    function lidarSubmit(evt) {
        evt.preventDefault();
        
            sendForm("service_pxhjzak","template_siiaa7m", evt.target, "VE0oyEp6f4iPZBGK4" )
        .then((result) => {
            alert("Enviado com sucesso!");
        }, (error) => {
            alert("Erro ao enviar : limite maximo mensal de Emails recebido.");
        });
    
    }

    
    return(<>
        <div className={styles.Embrulho}>
            <form className={styles.CaixaFormulario}
            onSubmit={lidarSubmit} >
                
                    <h2>Contate-me</h2>
                    <div className={styles.Informacao}>
                        <input type="hidden" value="Curriculo" />
                        <input type="text"
                        required
                        name="nomePessoa"
                        value={nomePessoa}
                        onChange={(e) => setnomepessoa(e.target.value)}
                        placeholder="Seu nome" />              
                        <input type="text"
                        name="dado_contato"
                        onChange={(e) => setdadoContato(e.target.value)}
                        value={dadoContato}
                        placeholder="Por onde posso te responder? (whats, Email... deixar o mais claro possivel)"/>
                        <input type="text"
                        required
                        name="assunto_email"
                        value={assuntoEmail}
                        onChange={(e) => setassuntoEmail(e.target.value)}
                        placeholder="Assunto do contato"/>    
                    </div>  
                    <p>Mensagem</p>
                    
                    <div>
                        <textarea rows="4"
                        required
                        name="mensagem_email"
                        value={mensagemEmail}
                        onChange={(e) => setmensagemEmail(e.target.value)}
                        placeholder="Sua mensagem...">
                        
                        </textarea>
                    </div>
                    
                    <input type="submit" value={"Enviar"} />
                



            </form>
        </div>


    </>);
}

export default FormularioComunicacao;
